#include<bits/stdc++.h>
using namespace std;
struct edge
{
    int to,val,nxt;
}e[500050];
int head[500050],l[21][21],tot=1;
int n,m,s,t,d[500050],now[500050];
void add1(int u,int v,int w)
{
    e[++tot]=(edge){v,w,head[u]};
    head[u]=tot;
}
void add(int u,int v,int w)
{
    add1(u,v,w);
    add1(v,u,0);
}
bool bfs()
{
    memset(d,0,sizeof(d));
    d[s]=1;
    queue<int> q;
    q.push(s);
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(int i=head[t];i;i=e[i].nxt)
        {
            int v=e[i].to,val=e[i].val;
            if(d[v]==0&&val)
            {
                d[v]=d[t]+1;
                q.push(v);
                if(v==::t)
                {
                    return true;
                }
            }
        }
    }
    return false;
}
int dfs(int x,int flow)
{
    if(x==t||flow==0)
    {
        return flow;
    }
    int sum=0;
    for(int i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        int v=e[i].to,val=e[i].val;
        if(d[v]==d[x]+1&&val)
        {
            int tmp=dfs(v,min(flow,val));
            e[i].val-=tmp;
            e[i^1].val+=tmp;
            sum+=tmp;
            flow-=tmp;
            if(flow==0)
            {
                break;
            }
        }
    }
    if(sum==0)
    {
        d[x]=0;
    }
    return sum;
}
int dinic()
{
    int ans=0;
    while(bfs())
    {
        memcpy(now,head,sizeof(head));
        while(int d=dfs(s,2e9))
        {
            ans+=d;
        }
    }
    return ans;
}
int fa[100010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    fa[find(x)]=find(y);
}
int main()
{
    int p;
    scanf("%d%d%d",&n,&l[0][0],&p);
    s=0;
    t=n+1;
    for(int i=1;i<=n+1;i++)
    {
        fa[i]=i;
    }
    for(int i=1;i<=l[0][0];i++)
    {
        scanf("%d%d",&l[0][i],&l[i][0]);
        for(int j=1;j<=l[i][0];j++)
        {
            scanf("%d",&l[i][j]);
            if(l[i][j]==-1)
            {
                l[i][j]=n+1;
            }
            if(j>1)
            {
                merge(l[i][j],l[i][j-1]);
            }
        }
    }
    if(find(0)!=find(n+1))
    {
        printf("0");
        return 0;
    }
    long long sum=0;
    for(int x=1;;x++)
    {
        for(int i=0;i<=n;i++)
        {
            add(i+(x-1)*(n+2),i+x*(n+2),2e9);
        }
        add(n+1+x*(n+2),n+1+(x-1)*(n+2),2e9);
        for(int i=1;i<=l[0][0];i++)
        {
            int tmp=(x-1)%l[i][0]+1;
            add(l[i][tmp]+(x-1)*(n+2),l[i][x%l[i][0]+1]+x*(n+2),l[0][i]);
        }
        sum+=dinic();
        if(sum>=p)
        {
            printf("%d\n",x);
            return 0;
        }
    }
    return 0;
}
